mapper.update:
update shop_verification_report
set running_ai_score_id = #{scoreId}, ai_score_updated_at = sysdate()
where report_id = #{reportId} and status = 'PUBLISHED'
  and ai_score_status = 'RUNNING' and running_ai_score_id is null
  and ai_score_version = #{promptVersion}
  and ai_score_input_hash = #{inputHash}

update shop_verification_report
set ai_score = #{score}, ai_score_status = 'SUCCEEDED', ai_scored_at = sysdate(),
    current_ai_score_id = #{scoreId}, ai_score_next_retry_at = null,
    running_ai_score_id = null, ai_score_updated_at = sysdate()
where report_id = #{reportId} and status = 'PUBLISHED'
  and ai_score_status = 'RUNNING'
  and running_ai_score_id = #{scoreId}
  and ai_score_version = #{promptVersion}
  and ai_score_input_hash = #{inputHash}

update shop_verification_report
set ai_score_status = case when ai_score_attempts < #{maxAttempts}
                           then 'PENDING' else 'FAILED' end,
    ai_score_next_retry_at = case when ai_score_attempts < #{maxAttempts}
                                  then date_add(sysdate(), interval #{retryDelaySeconds} second)
                                  else null end,
    running_ai_score_id = null, ai_score_updated_at = sysdate()
where report_id = #{reportId} and status = 'PUBLISHED'
  and ai_score_status = 'RUNNING'
  and running_ai_score_id = #{scoreId}
  and ai_score_version = #{promptVersion}
  and ai_score_input_hash = #{inputHash}
